import { useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../api/axios';

export default function ForgotPassword() {
  const [email, setEmail] = useState('');
  const [sent, setSent] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await api.post('/auth/forgot-password', { email });
      setSent(true);
    } catch (err) {
      setError(err.response?.data?.message || 'Something went wrong');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.container}>
      <div style={s.card}>
        <h2 style={{ margin: '0 0 0.25rem' }}>Forgot Password</h2>
        <p style={s.sub}>Enter your email and we'll send you a reset link.</p>

        {sent ? (
          <div style={s.success}>
            ✅ Reset link sent! Check your inbox (and spam folder).
            <br /><br />
            <Link to="/login">← Back to Login</Link>
          </div>
        ) : (
          <form onSubmit={handleSubmit}>
            {error && <div style={s.error}>{error}</div>}
            <label style={s.label}>Email Address</label>
            <input style={s.input} type="email" placeholder="your@email.com" required
              value={email} onChange={(e) => setEmail(e.target.value)} />
            <button style={s.btn} type="submit" disabled={loading}>
              {loading ? 'Sending...' : 'Send Reset Link'}
            </button>
            <p style={{ textAlign: 'center', marginTop: '1rem' }}>
              <Link to="/login">← Back to Login</Link>
            </p>
          </form>
        )}
      </div>
    </div>
  );
}

const s = {
  container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', background: '#f0f2f5' },
  card: { background: '#fff', padding: '2rem', borderRadius: '10px', width: '360px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)' },
  sub: { color: '#6b7280', fontSize: '0.85rem', marginBottom: '1.5rem' },
  label: { display: 'block', fontSize: '0.8rem', fontWeight: 700, color: '#374151', marginBottom: '0.3rem' },
  input: { display: 'block', width: '100%', padding: '0.6rem 0.75rem', marginBottom: '1rem', borderRadius: '6px', border: '1px solid #d1d5db', boxSizing: 'border-box', fontSize: '0.9rem' },
  btn: { width: '100%', padding: '0.7rem', background: '#4f46e5', color: '#fff', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 700 },
  error: { background: '#fee2e2', color: '#dc2626', padding: '0.5rem 0.75rem', borderRadius: '6px', marginBottom: '1rem', fontSize: '0.88rem' },
  success: { background: '#d1fae5', color: '#065f46', padding: '1rem', borderRadius: '6px', fontSize: '0.9rem' },
};
